import torch

def safe_acceptance_ratio(p_t: float, p_d: float, log_space: bool = False) -> float:
    """Compute min(1, p_t/p_d) safely."""
    if log_space:
        # Compare in log space to avoid float underflow at low temperature
        import math
        log_pt = math.log(max(p_t, 1e-40))
        log_pd = math.log(max(p_d, 1e-40))
        return 1.0 if log_pt >= log_pd else math.exp(log_pt - log_pd)
    return min(1.0, p_t / max(p_d, 1e-9))
